sequence.script:
// ---------- Utility: Normalize WSO2 property to proper JS object ----------
function normalize(obj) {
    if (obj == null) return null;

    // If already JS object/array
    if (typeof obj === "object" && !(obj instanceof java.lang.String)) {
        return obj;
    }

    // Convert Java object or string → JSON
    try {
        return JSON.parse(String(obj));
    } catch (e) {
        return obj;
    }
}

// ---------- Read and normalize properties ----------
var claimsResponse      = normalize(mc.getProperty("claimResponse"));
var inspectionsResponse = normalize(mc.getProperty("inspectionsResponse"));
var lossitemsResponse   = normalize(mc.getProperty("lossResponse"));

// ---------- Initialize ----------
var valid = true;
var error = null;

// ---------- Extract first loss item ----------
var lossItem = null;

if (lossitemsResponse && lossitemsResponse.length > 0) {
    lossItem = lossitemsResponse[0];
}

// ---------- Debug (very useful) ----------
mc.setProperty("DEBUG_claimsResponse", JSON.stringify(claimsResponse));
mc.setProperty("DEBUG_lossitemsResponse", JSON.stringify(lossitemsResponse));
mc.setProperty("DEBUG_lossItem", JSON.stringify(lossItem));

// ---------- 1. Claim status validation ----------
if (claimsResponse &&
   (claimsResponse.claimStatusCode === "REJECTED" ||
    claimsResponse.claimStatusCode === "SETTLED" ||
    claimsResponse.claimStatusCode === "COMPLETED")) {

    valid = false;
    error = "Reserve is not applicable for Rejected or settled or completed Claim";
}

// ---------- 2. LossItemIdentifier check ----------
else if (!lossItem || !lossItem.lossItemIdentifier) {

    valid = false;
    error = "related LossItemIdentifier must exist under the claim for creating the reserve";
}

// ---------- 3. Loss status validation ----------
else if (lossItem.lossStatus === "REJECTED" ||
         lossItem.lossStatus === "CLOSED" ||
         lossItem.lossStatus === "SETTLED") {

    valid = false;
    error = "The loss status must not be REJECTED, CLOSED, or SETTLED.";
}

// ---------- 4. Date validation ----------
else if (lossItem.reportedDateTime && lossItem.incidentDateTime) {

    var reportedDate = new Date(lossItem.reportedDateTime);
    var incidentDate = new Date(lossItem.incidentDateTime);

    if (reportedDate < incidentDate) {
        valid = false;
        error = "reserveEffectiveDate Cannot be before FNOL date";
    }
}

// ---------- Final result ----------
mc.setProperty("validationValid", valid);
mc.setProperty("validationError", error);

then.script:
// ---------- Utility: Normalize WSO2 property to proper JS object ----------
function normalize(obj) {
    if (obj == null) return null;

    if (typeof obj === "object" && !(obj instanceof java.lang.String)) {
        return obj;
    }

    try {
        return JSON.parse(String(obj));
    } catch (e) {
        return obj;
    }
}

// ---------- Read and normalize properties ----------
var claimResponse    = normalize(mc.getProperty("claimResponse"));
var lossResponse     = normalize(mc.getProperty("lossResponse"));
var coverageResponse = normalize(mc.getProperty("coverageResponse"));

var reserveType = mc.getProperty("reserveType");
var reason      = mc.getProperty("reason");
var setBy       = mc.getProperty("setBy");

// ---------- Extract loss item ----------
var lossItem = null;

if (lossResponse && lossResponse.length > 0) {
    lossItem = lossResponse[0];
}

// ---------- Extract coverage item (FIXED) ----------
var coverageItem = null;

if (coverageResponse && coverageResponse.length > 0) {
    coverageItem = coverageResponse[0];
}

// ---------- Extract limit amount (FIXED) ----------
var limitAmount = null;

if (coverageItem &&
    coverageItem.coverages &&
    coverageItem.coverages.length > 0 &&
    coverageItem.coverages[0].limits &&
    coverageItem.coverages[0].limits.length > 0) {

    limitAmount = coverageItem.coverages[0].limits[0].limitAmount;
}

// ---------- Fallback handling for reason ----------
if (!reason || reason === "") {
    reason = "No reason provided";
}

// ---------- Construct final payload ----------
var reserveRequest = {
    reserveType: reserveType,
    reserveCategory: claimResponse ? claimResponse.claimType : null,
    reserveAmount: {
        amount: limitAmount,
        currency: lossItem ? lossItem.currencyCode : null
    },
    reason: reason,
    reserveEffectiveDate: lossItem ? lossItem.reportedDateTime : null,
    setBy: setBy,
    relatedLossItemIdentifier: lossItem ? lossItem.lossItemIdentifier : null
};

// ---------- Set payload ----------
mc.setPayloadJSON(reserveRequest);
